1210	  if (it.source_type === 'registry') {
1211	    const inspectText =
1212	      it.kind === 'skill'
1213	        ? (it.body || '')
1214	        : JSON.stringify(it.neutral || {});
1215	    const pi = security.detectPI(inspectText);
1216	    if (pi.length > 0) {
1217	      if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(inspectText));
1218	      if (piAck === 'exclude') return { applied: false, reason: 'excluded', kind: it.kind, id };
1219	      if (piAck === 'mask') {
1220	        if (it.kind === 'skill') it = { ...it, body: security.mask(it.body || '') };
1221	        else it = { ...it, neutral: JSON.parse(security.mask(JSON.stringify(it.neutral || {}))) };
1222	      }
1223	      // 'proceed' → 그대로
1224	    }
1225	  }
1226	
1227	  if (it.kind === 'skill') {
1228	    let name = it.name;
1229	    if (canonical.skillExists(name) && !resolution) {
1230	      const cur = canonical.readSkill(name);
1231	      return { conflict: true, kind: 'skill', name, options: ['overwrite', 'skip', 'rename'],
1232	        diff: diff.lineDiff(cur.body, it.body || '') };
1233	    }
1234	    if (canonical.skillExists(name) && resolution === 'skip') return { applied: false, skipped: true, kind: 'skill', name };
1235	    if (canonical.skillExists(name) && resolution === 'rename') name = newName || name + '-2';
1236	    const tags = category.normalizeTags(it.tags || []);
1237	    canonical.writeSkill(name, it.body || '', { source_id: 'catalog', source_tool: 'bundled', official: it.official !== false, tags });
1238	    if (tags.length) category.registerCustom(tags);
1239	    gitCommit(`store install skill: ${name}`);
1240	    return { applied: true, kind: 'skill', name, results: skillPushAll({ name, apply: true }) };
1241	  }
1242	
1243	  if (it.kind === 'agent') {
1244	    const neutral = { ...it.neutral, tags: category.normalizeTags(it.tags || []) };
1245	    if (canonical.agentExists(neutral.id) && !resolution) {
1246	      const cur = canonical.readAgent(neutral.id);
1247	      return { conflict: true, kind: 'agent', id: neutral.id, options: ['overwrite', 'skip', 'rename'],
1248	        diff: diff.lineDiff(JSON.stringify(cur, null, 2), JSON.stringify(neutral, null, 2)) };
1249	    }
1250	    if (canonical.agentExists(neutral.id) && resolution === 'skip') return { applied: false, skipped: true, kind: 'agent', id: neutral.id };
1251	    if (canonical.agentExists(neutral.id) && resolution === 'rename') {
1252	      const nm = newName || neutral.name + '-2';
1253	      neutral.name = nm;
1254	      neutral.id = 'agent-' + nm;
1255	    }
1256	    canonical.writeAgent(neutral);
1257	    if (neutral.tags.length) category.registerCustom(neutral.tags);
1258	    gitCommit(`store install agent: ${neutral.id}`);
1259	    return { applied: true, kind: 'agent', id: neutral.id, results: agentPushAll({ id: neutral.id, apply: true }) };
1260	  }
