// ================= 로컬 폴더 열기 (이슈4) / 항목 본문 보기 (이슈5) =================

// (보안 가드) "폴더 열기"가 허용되는 디렉토리 화이트리스트를 만든다.
//  ① 등록된 프로젝트 scope 경로(projects 레지스트리의 root 목록)
//  ② 각 모델 홈의 skills/agents 디렉토리(paths.js 기존 함수로 도출) + .agents/skills(공유)
// 반환: 정규화(realpath)된 허용 디렉토리 절대경로 Set. 존재하지 않는 경로도
// 후보로 포함하되(열 때 존재 검사), realpath는 존재하는 것만 성공하므로 비교는
// 후보(candidate)와 target 둘 다 realpath로 정규화한 값끼리 한다.
function openPathAllowedDirs() {
  const dirs = [];
  // ① 등록된 프로젝트 root
  for (const p of projects.list()) dirs.push(p.root);
  // ② 모델 홈의 skills/agents + 공유 skills
  for (const tool of paths.TOOLS) {
    try { dirs.push(paths.skillTargetDir(tool)); } catch { /* 무시 */ }
    try { dirs.push(paths.agentDir(tool)); } catch { /* 무시 */ }
  }
  try { dirs.push(path.join(paths.agentsHome(), 'skills')); } catch { /* 무시 */ }
  // ①-추가: 등록된 프로젝트의 스킬/에이전트 폴더도 허용(프로젝트 행에서 열기).
  for (const p of projects.list()) {
    for (const src of paths.projectSkillSources(p.root)) dirs.push(src.dir);
    for (const tool of paths.TOOLS) {
      try { dirs.push(paths.projectAgentDir(p.root, tool)); } catch { /* 무시 */ }
    }
  }
  // 중복 제거(문자열 기준).
  return [...new Set(dirs.map((d) => path.resolve(d)))];
}

// target 디렉토리가 화이트리스트 중 하나이거나 그 하위인지 realpath 기준으로 판정.
// 심볼릭 링크 우회를 막기 위해 target·candidate 모두 fs.realpathSync로 정규화 후 비교한다.
function isDirWithinAllowed(targetDir) {
  let realTarget;
  try { realTarget = fs.realpathSync(targetDir); } catch { return false; }
  for (const cand of openPathAllowedDirs()) {
    let realCand;
    try { realCand = fs.realpathSync(cand); } catch { continue; } // 존재하지 않는 후보는 건너뜀
    if (realTarget === realCand) return true;
    // realTarget이 realCand의 하위인지(경계 안전한 접두 비교).
    const prefix = realCand.endsWith(path.sep) ? realCand : realCand + path.sep;
    if (realTarget.startsWith(prefix)) return true;
  }
  return false;
}

// (이슈4) 로컬 경로를 macOS Finder에서 연다. 화이트리스트 밖은 거부(에러).
//  - scope='global' + kind가 오면 각 모델 skills/agents 폴더 중 존재하는 첫 경로를 연다.
//  - 파일 경로면 그 부모 폴더를 연다.
//  - 허용되면 execFile 계열(execFileSync)로 비셸 `open <dir>` 실행 → {opened:true, path}.
function openLocalPath({ path: p, scope, kind } = {}) {
  let targetDir = null;

  // 전역(~) 항목: 각 모델의 skills(또는 agents) 폴더 중 존재하는 첫 경로를 연다.
  if (!p && scope === 'global') {
    const wantAgent = kind === 'agent';
    const candidates = [];
    for (const tool of paths.TOOLS) {
      candidates.push(wantAgent ? paths.agentDir(tool) : paths.skillTargetDir(tool));
    }
    if (!wantAgent) candidates.push(path.join(paths.agentsHome(), 'skills'));
    targetDir = candidates.find((d) => { try { return fs.statSync(d).isDirectory(); } catch { return false; } }) || null;
    if (!targetDir) throw new Error('열 수 있는 전역 폴더가 없습니다(폴더가 아직 없음)');
  } else {
    if (!p) throw new Error('경로(path)가 필요합니다');
    const abs = path.resolve(p);
    let st;
    try { st = fs.statSync(abs); } catch { throw new Error('경로가 존재하지 않습니다: ' + abs); }
    // 파일이면 부모 폴더를 연다.
    targetDir = st.isDirectory() ? abs : path.dirname(abs);
  }

  // 화이트리스트 가드(필수) — 밖이면 거부.
  if (!isDirWithinAllowed(targetDir)) {
    throw new Error('허용되지 않은 경로입니다(화이트리스트 밖): ' + targetDir);
  }

  // 실제 열기: 비셸 execFile 계열. macOS `open`. (플랫폼 방어: darwin만.)
  if (process.platform !== 'darwin') {
    throw new Error('이 기능은 macOS에서만 지원됩니다');
  }
  execFileSync('open', [targetDir], { stdio: 'ignore' });
  return { opened: true, path: targetDir };
}

// (이슈5) 스킬/에이전트의 (scope,name) 본문을 요청 도구(미지정이면 존재하는 첫 도구)로 읽는다.
//  - scanner.readItemContent 재사용 → 거부목록/PI 게이트 자동 상속.
//  - 반환: { name, kind, tool, path, body, tools:[존재 모델 목록] }.
//  - PI 감지 시 PiGateError를 던진다(서버가 409로 노출, 기존 pull 패턴과 동일).
function itemContent({ kind, name, scope, tool } = {}) {
  if (kind !== 'skill' && kind !== 'agent') {
    throw new Error("알 수 없는 kind: " + kind + " ('skill'|'agent')");
  }
  if (!name) throw new Error('name이 필요합니다');

  // 해당 (scope,name)의 도구별 파일 경로를 모은다. scope는 'global' 또는 프로젝트 root.
  const isProject = scope && scope !== 'global';
  const projRoot = isProject ? requireRegisteredProject(scope) : null;
  const byTool = {}; // tool -> filePath (존재하는 것만)

  if (kind === 'skill') {
    // 발견된 스킬 중 (scope,name) 일치 항목을 도구 슬롯으로 역매핑(매트릭스와 동일 규칙).
    const GLOBAL_SLOT = { claude: 'claude-user', codex: 'shared-agents' };
    const PROJECT_SLOT = { claude: 'claude-project', codex: 'shared-project' };
    const slotMap = isProject ? PROJECT_SLOT : GLOBAL_SLOT;
    for (const s of scanner.discoverSkills()) {
      if (s.name !== name) continue;
      const sScope = s.scope === 'project' ? s.projectRoot : 'global';
      if (isProject ? sScope !== projRoot : sScope !== 'global') continue;
      const t = paths.TOOLS.find((x) => slotMap[x] === s.source_id);
      if (t && !byTool[t]) byTool[t] = s.path;
    }
  } else {
    for (const a of scanner.discoverAgents().agents) {
      if (a.name !== name) continue;
      const aScope = a.scope === 'project' ? a.projectRoot : 'global';
      if (isProject ? aScope !== projRoot : aScope !== 'global') continue;
      if (!byTool[a.tool]) byTool[a.tool] = a.path;
    }
  }

  const toolsPresent = paths.TOOLS.filter((t) => byTool[t]);
  if (!toolsPresent.length) {
    throw new Error(`${kind} "${name}"의 파일을 찾을 수 없습니다 (scope: ${scope || 'global'})`);
  }
  // 요청 도구(있고 존재하면) 우선, 아니면 존재하는 첫 도구.
  const useTool = (tool && byTool[tool]) ? tool : toolsPresent[0];
  const filePath = byTool[useTool];

  // readItemContent 재사용 — 거부목록/PI 게이트 상속.
  const { text, pi } = scanner.readItemContent({ path: filePath });
  if (pi.length > 0) {
    // 본문 뷰어도 pull과 동일하게 PI 게이트를 적용(마스킹 후 보기/취소는 UI가 처리).
    throw new PiGateError(pi, security.maskedSensitiveLines(text));
  }
  return { name, kind, tool: useTool, path: filePath, body: text, tools: toolsPresent };
}

module.exports = {
  CANON_ID,
  PiGateError,
  openLocalPath,
  itemContent,

// --- 로컬 폴더 열기 (이슈4, core 호출만) ---
if (req.method === 'POST' && route === '/open-path') {
  const b = await readBody(req);
  // 화이트리스트 가드는 core.openLocalPath가 강제한다. 거부/실패는 아래 공통 catch가 4xx/500 JSON으로.
  return sendJson(res, 200, core.openLocalPath({ path: b.path, scope: b.scope, kind: b.kind }));
}

// --- 스킬/에이전트 본문 뷰어 (이슈5, core 호출만) ---
if (req.method === 'GET' && route === '/item/content') {
  try {
    return sendJson(res, 200, core.itemContent({
      kind: url.searchParams.get('kind'),
      name: url.searchParams.get('name'),
      scope: url.searchParams.get('scope') || undefined,
      tool: url.searchParams.get('tool') || undefined,
    }));
  } catch (e) {
    if (e instanceof core.PiGateError) {
      // PI 게이트: 409 + 감지 내용 → 프런트가 PI 모달(마스킹 후 보기/취소)을 띄운다.
      return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
    }
    throw e;
  }
}

