input.new_string:
// 등록/해제 후 스킬·에이전트 목록 새로고침(열려 있으면).
function refreshAfterProjectChange() {
  if (loaded.skills) loadSkillOverview();
  if (loaded.agents) loadAgentOverview();
}

// ===================== 전체화면 본문 뷰어 (이슈5) =====================
// 스킬/에이전트 (scope,name)의 모델별 파일 본문을 전체화면 오버레이로 보여준다.
//  · 헤더: 이름 + 파일 경로 + 모델 탭(존재 모델들 — 어긋남이면 탭 전환으로 비교) + [닫기].
//  · 본문: 마크다운 원문 그대로 <pre>(읽기 전용, 가로 스크롤 내부 처리).
//  · ESC로 닫기. 로딩 중 "불러오는 중…", 실패 시 재시도. PI 409면 PI 모달(마스킹 후 보기/취소).
let viewerCtx = null; // {kind, name, scope, tool, tools} — 현재 뷰어 상태(탭 전환·PI 재시도).

// 뷰어 열기: (kind, name, scope) — 상세 슬라이드오버가 열려 있으면 닫고 전체화면으로.
function openContentViewer(kind, name, scope, tool) {
  closePanel();
  viewerCtx = { kind, name, scope: scope || 'global', tool: tool || null, tools: [] };
  $('#viewer-title').textContent = name;
  $('#viewer-path').textContent = '';
  $('#viewer-tabs').innerHTML = '';
  $('#content-viewer').hidden = false;
  loadViewerContent();
}

// 현재 viewerCtx로 /item/content 조회 후 렌더. piAck는 PI 모달 재시도용.
async function loadViewerContent(piAck) {
  if (!viewerCtx) return;
  const { kind, name, scope, tool } = viewerCtx;
  $('#viewer-body').innerHTML = '<div class="skel">불러오는 중…</div>';
  const qs = '/item/content?kind=' + encodeURIComponent(kind) + '&name=' + encodeURIComponent(name)
    + '&scope=' + encodeURIComponent(scope)
    + (tool ? '&tool=' + encodeURIComponent(tool) : '');
  // piAck는 GET 쿼리로 전달(서버 itemContent는 piAck를 받지 않으므로 여기선 마스킹 미지원 —
  //   409면 PI 모달을 띄우되 '그대로 진행/제외'가 아닌 안내만: 재시도는 같은 요청). 아래 fetch 참고.
  const res = await fetch(qs);
  if (res.status === 409) {
    // PI 게이트: 기존 PI 모달 재사용. 뷰어 컨텍스트를 걸어 ack 시 다시 시도(마스킹 후 보기).
    const info = await res.json().catch(() => ({}));
    showPiModal(info);
    return;
  }
  if (!res.ok) {
    const msg = await errMsg(res);
    $('#viewer-body').innerHTML =
      `<div class="empty-state">이슈가 생겼습니다 — ${esc(msg)}
        <span class="inline-acts" style="justify-content:center;margin-top:10px">
          <button class="btn btn-secondary btn-sm" id="viewer-retry">다시 시도</button>
        </span></div>`;
    const rb = $('#viewer-retry');
    if (rb) rb.addEventListener('click', () => loadViewerContent());
    return;
  }
  const d = await res.json();
  viewerCtx.tools = d.tools || [];
  viewerCtx.tool = d.tool; // 실제로 읽은 도구로 확정(탭 활성 표시).
  renderViewer(d);
}

function renderViewer(d) {
  $('#viewer-title').textContent = viewerCtx.name;
  $('#viewer-path').textContent = d.path || '';
  $('#viewer-path').title = d.path || '';
  // 모델 탭: 존재하는 모델들. 하나뿐이면 탭은 그냥 라벨로 표시(전환 불필요).
  const tabs = (d.tools || []).map((t) =>
    `<button class="viewer-tab ${t === d.tool ? 'active' : ''}" data-viewer-tool="${esc(t)}">
      <span class="tool-dot" style="background:${TOOL_COLOR[t] || 'var(--st-muted)'}"></span>${esc(t)}
    </button>`).join('');
  $('#viewer-tabs').innerHTML = tabs;
  // 본문: 마크다운 원문 그대로 <pre>(가로 스크롤은 .viewer-pre 내부).
  $('#viewer-body').innerHTML = `<pre class="viewer-pre">${esc(d.body || '')}</pre>`;
}

// 모델 탭 전환 → 그 도구 본문을 다시 읽어 비교.
function switchViewerTool(tool) {
  if (!viewerCtx || viewerCtx.tool === tool) return;
  viewerCtx.tool = tool;
  loadViewerContent();
}

function closeContentViewer() {
  $('#content-viewer').hidden = true;
  viewerCtx = null;
}

// ===================== 이벤트 위임 =====================

