/* ===========================================================================
   이슈5: 전체화면 본문 뷰어 (스킬/에이전트 마크다운 원문)
   panel(50)·scrim(40) 위, PI 모달(modal-scrim 60)·토스트(70) 아래로 둔다
   → 본문 조회 중 PI 409가 오면 PI 모달이 뷰어 위에 정상 표시된다.
   =========================================================================== */
.viewer {
  position: fixed; inset: 0; z-index: 55; background: var(--color-canvas);
  display: flex; flex-direction: column;
}
.viewer-head {
  display: flex; align-items: center; gap: 14px; flex-wrap: wrap;
  padding: 14px 20px; border-bottom: 1px solid var(--color-hairline);
  background: var(--color-canvas);
}
.viewer-titles { min-width: 0; margin-right: auto; }
.viewer-title { font-size: 17px; font-weight: 650; letter-spacing: -0.2px; }
.viewer-path {
  font-family: ui-monospace, Menlo, monospace; font-size: 11.5px; color: var(--st-muted);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 46vw;
}
.viewer-tabs { display: flex; gap: 6px; flex-wrap: wrap; }
.viewer-tab {
  display: inline-flex; align-items: center; gap: 6px; cursor: pointer;
  font: inherit; font-size: 12.5px; padding: 5px 12px; border-radius: 999px;
  border: 1px solid var(--color-hairline); background: var(--color-canvas); color: var(--color-ink);
}
.viewer-tab.active { background: var(--color-canvas-parchment); border-color: var(--color-ink); font-weight: 600; }
.viewer-body { flex: 1; min-height: 0; overflow: auto; padding: 20px; }
.viewer-pre {
  margin: 0; font-family: ui-monospace, Menlo, monospace; font-size: 13px; line-height: 1.6;
  color: var(--color-ink); white-space: pre; overflow-x: auto;
  background: var(--color-canvas-parchment); border: 1px solid var(--color-hairline);
  border-radius: var(--radius-lg); padding: 18px 20px;
}
@media (max-width: 1023.98px) {
  .viewer-path { max-width: 100%; white-space: normal; }
  .viewer-head { padding: 12px 14px; }
  .viewer-body { padding: 14px; }
}

