    await new Promise(r=>setTimeout(r, 500));
    results.folderSelected = document.querySelector('#skill-folder-list .mdf-item.active .mdf-label')?.textContent;
    results.scopeColHidden = document.querySelector('#skill-mx-table').classList.contains('mx-hide-scope');
    // colspan 정합: 폴더 선택 시 6.
    const emptyOrRow = document.querySelector('#skill-mx-rows tr td[colspan]');
    results.folderColspan = emptyOrRow ? emptyOrRow.getAttribute('colspan') : 'rows-present';
  }
  return JSON.stringify(results, null, 1);
})()

